        boolean shouldWriteBom = writeBom && !self.toFile().exists();
        if (append) {
            BufferedWriter writer = Files.newBufferedWriter(self, Charset.forName(charset), CREATE, APPEND);
            if (shouldWriteBom) {
                IOGroovyMethods.writeUTF16BomIfRequired(writer, charset);
