            return writer;
        } else {
            OutputStream out = Files.newOutputStream(self);
            if (shouldWriteBom) {
                IOGroovyMethods.writeUTF16BomIfRequired(out, charset);
            }
            return new BufferedWriter(new OutputStreamWriter(out, Charset.forName(charset)));
        }
    }


